import React, { useState } from 'react';
import { SERVICES_LIST } from '../constants';
import { ReservationStatus } from '../types';

// Mock function to generate days
const getNextDays = (days: number) => {
  const result = [];
  const today = new Date();
  for (let i = 0; i < days; i++) {
    const d = new Date(today);
    d.setDate(today.getDate() + i);
    result.push(d);
  }
  return result;
};

// Mock time slots
const timeSlots = ['09:00', '10:30', '13:00', '14:30', '16:00', '17:30'];

const ReservationSystem: React.FC = () => {
  const [selectedService, setSelectedService] = useState<number | null>(null);
  const [selectedDate, setSelectedDate] = useState<string | null>(null);
  const [selectedTime, setSelectedTime] = useState<string | null>(null);
  const [formData, setFormData] = useState({
    name: '',
    email: '',
    phone: '',
    note: ''
  });
  const [submitted, setSubmitted] = useState(false);

  const days = getNextDays(14); // Next 2 weeks

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    // Here we would call the API to save to MySQL
    console.log("Submitting reservation:", {
        ...formData,
        serviceId: selectedService,
        date: selectedDate,
        time: selectedTime,
        status: ReservationStatus.PENDING
    });

    // Simulate API delay
    setTimeout(() => {
        setSubmitted(true);
    }, 1000);
  };

  const resetForm = () => {
    setSubmitted(false);
    setSelectedService(null);
    setSelectedDate(null);
    setSelectedTime(null);
    setFormData({ name: '', email: '', phone: '', note: '' });
  };

  if (submitted) {
    return (
      <div className="text-center p-12 bg-deep-green border border-gold rounded-lg shadow-xl max-w-3xl mx-auto mt-10">
        <h3 className="text-3xl text-gold font-serif mb-4">Děkuji za rezervaci!</h3>
        <p className="text-white mb-6">Vaše rezervace byla přijata ke zpracování. Potvrzení Vám přijde na e-mail.</p>
        <button onClick={resetForm} className="text-gold underline hover:text-white">Vytvořit novou rezervaci</button>
      </div>
    );
  }

  return (
    <section id="reservation" className="py-20 bg-deep-green">
      <div className="max-w-4xl mx-auto px-4 sm:px-6">
        <div className="text-center mb-12">
          <h2 className="text-3xl md:text-5xl font-serif text-gold mb-4">Rezervace</h2>
          <p className="text-gray-300">Vyberte si službu, termín a zarezervujte si svůj čas pro regeneraci.</p>
        </div>

        <div className="bg-[#0f3d26] p-6 md:p-10 rounded-xl shadow-2xl border border-gold/10">
          {/* Step 1: Service Selection */}
          <div className="mb-8">
            <h3 className="text-xl text-white mb-4 font-serif border-b border-gold/30 pb-2">1. Výběr služby</h3>
            <div className="grid grid-cols-1 sm:grid-cols-2 gap-4">
              {SERVICES_LIST.map((service) => (
                <button
                  key={service.id}
                  onClick={() => setSelectedService(service.id)}
                  className={`p-4 rounded-lg text-left transition-all ${
                    selectedService === service.id
                      ? 'bg-gold text-deep-green font-bold shadow-lg scale-105'
                      : 'bg-deep-green border border-gray-600 text-gray-300 hover:border-gold'
                  }`}
                >
                  <div className="flex justify-between">
                    <span>{service.title}</span>
                    <span>{service.price}</span>
                  </div>
                </button>
              ))}
            </div>
          </div>

          {/* Step 2: Date & Time Selection (Only if service selected) */}
          {selectedService && (
            <div className="mb-8 animate-fade-in">
              <h3 className="text-xl text-white mb-4 font-serif border-b border-gold/30 pb-2">2. Výběr termínu</h3>

              {/* Simple Day Scroller */}
              <div className="flex overflow-x-auto pb-4 gap-2 mb-4 scrollbar-thin">
                {days.map((day) => {
                   const dateStr = day.toISOString().split('T')[0];
                   const isSelected = selectedDate === dateStr;
                   return (
                    <button
                        key={dateStr}
                        onClick={() => { setSelectedDate(dateStr); setSelectedTime(null); }}
                        className={`flex-shrink-0 w-20 p-2 rounded-md text-center border ${
                            isSelected ? 'bg-gold border-gold text-deep-green' : 'border-gray-600 text-gray-300 hover:border-gold'
                        }`}
                    >
                        <div className="text-xs uppercase">{day.toLocaleDateString('cs-CZ', { weekday: 'short' })}</div>
                        <div className="text-lg font-bold">{day.getDate()}.{day.getMonth() + 1}.</div>
                    </button>
                   );
                })}
              </div>

              {/* Time Slots */}
              {selectedDate && (
                  <div className="grid grid-cols-3 sm:grid-cols-6 gap-2">
                      {timeSlots.map((time) => (
                          <button
                            key={time}
                            onClick={() => setSelectedTime(time)}
                            className={`p-2 rounded text-center ${
                                selectedTime === time ? 'bg-white text-deep-green font-bold' : 'bg-deep-green border border-gray-600 text-white hover:bg-[#1a4f33]'
                            }`}
                          >
                              {time}
                          </button>
                      ))}
                  </div>
              )}
            </div>
          )}

          {/* Step 3: Contact Info */}
          {selectedTime && (
            <form onSubmit={handleSubmit} className="animate-fade-in">
                <h3 className="text-xl text-white mb-4 font-serif border-b border-gold/30 pb-2">3. Kontaktní údaje</h3>
                <div className="grid grid-cols-1 md:grid-cols-2 gap-4 mb-4">
                    <input 
                        type="text" 
                        required 
                        placeholder="Jméno a Příjmení"
                        value={formData.name}
                        onChange={e => setFormData({...formData, name: e.target.value})}
                        className="bg-deep-green border border-gray-600 p-3 rounded text-white focus:border-gold outline-none"
                    />
                     <input 
                        type="tel" 
                        required 
                        placeholder="Telefon"
                        value={formData.phone}
                        onChange={e => setFormData({...formData, phone: e.target.value})}
                        className="bg-deep-green border border-gray-600 p-3 rounded text-white focus:border-gold outline-none"
                    />
                     <input 
                        type="email" 
                        required 
                        placeholder="E-mail"
                        value={formData.email}
                        onChange={e => setFormData({...formData, email: e.target.value})}
                        className="bg-deep-green border border-gray-600 p-3 rounded text-white focus:border-gold outline-none"
                    />
                </div>
                <textarea 
                    placeholder="Poznámka pro Terezu..."
                    value={formData.note}
                    onChange={e => setFormData({...formData, note: e.target.value})}
                    className="w-full bg-deep-green border border-gray-600 p-3 rounded text-white focus:border-gold outline-none h-24 mb-6"
                ></textarea>

                <button 
                    type="submit" 
                    className="w-full bg-gold text-deep-green font-bold text-xl py-4 rounded hover:bg-gold-light transition shadow-lg"
                >
                    Dokončit rezervaci
                </button>
            </form>
          )}
        </div>
      </div>
    </section>
  );
};

export default ReservationSystem;

