const AdminPanel: React.FC = () => {
  const [isAuthenticated, setIsAuthenticated] = useState(false);
  const [password, setPassword] = useState('');
  const [reservations, setReservations] = useState(MOCK_RESERVATIONS);

  const handleLogin = (e: React.FormEvent) => {
    e.preventDefault();
    if (password === ADMIN_PASSWORD_HASH) {
      setIsAuthenticated(true);
    } else {
      alert("Nesprávné heslo");
    }
  };

  const updateStatus = (id: number, status: ReservationStatus) => {
    setReservations(reservations.map(res => 
      res.id === id ? { ...res, status } : res
    ));
  };

  if (!isAuthenticated) {
    return (
      <div className="min-h-screen flex items-center justify-center bg-deep-green">
        <form onSubmit={handleLogin} className="bg-[#0f3d26] p-8 rounded border border-gold/30">
          <h2 className="text-gold text-2xl mb-4 font-serif text-center">Admin Přihlášení</h2>
          <input 
            type="password" 
            value={password}
            onChange={(e) => setPassword(e.target.value)}
            className="w-full p-2 mb-4 bg-deep-green border border-gray-600 text-white rounded"
            placeholder="Heslo"
          />
          <button type="submit" className="w-full bg-gold text-deep-green font-bold py-2 rounded">Vstoupit</button>
        </form>
      </div>
    );
  }

  return (
    <div className="min-h-screen bg-deep-green p-4 sm:p-8">
      <div className="max-w-7xl mx-auto">
        <header className="flex justify-between items-center mb-8 border-b border-gold/30 pb-4">
            <h1 className="text-3xl text-gold font-serif">Správa Masáží - Admin</h1>
            <button onClick={() => setIsAuthenticated(false)} className="text-gray-400 hover:text-white">Odhlásit</button>
        </header>

        <div className="grid grid-cols-1 gap-8">
            {/* Reservation List */}
            <div className="bg-[#0f3d26] p-6 rounded-lg border border-gold/20">
                <h2 className="text-xl text-white mb-4">Rezervace</h2>
                <div className="overflow-x-auto">
                    <table className="w-full text-left text-sm text-gray-300">
                        <thead className="text-gold uppercase bg-deep-green">
                            <tr>
                                <th className="p-3">Datum</th>
                                <th className="p-3">Čas</th>
                                <th className="p-3">Klient</th>
                                <th className="p-3">Kontakt</th>
                                <th className="p-3">Stav</th>
                                <th className="p-3">Akce</th>
                            </tr>
                        </thead>
                        <tbody>
                            {reservations.map(res => (
                                <tr key={res.id} className="border-b border-gray-700 hover:bg-white/5">
                                    <td className="p-3">{res.date}</td>
                                    <td className="p-3">{res.time}</td>
                                    <td className="p-3">{res.clientName}</td>
                                    <td className="p-3">
                                        <div>{res.phone}</div>
                                        <div className="text-xs text-gray-500">{res.email}</div>
                                    </td>
                                    <td className="p-3">
                                        <span className={`px-2 py-1 rounded text-xs font-bold ${
                                            res.status === 'confirmed' ? 'bg-green-600 text-white' :
                                            res.status === 'cancelled' ? 'bg-red-600 text-white' :
                                            'bg-yellow-600 text-white'
                                        }`}>
                                            {res.status === 'pending' ? 'Nová' : res.status === 'confirmed' ? 'Potvrzeno' : 'Zrušeno'}
                                        </span>
                                    </td>
                                    <td className="p-3 space-x-2">
                                        {res.status === 'pending' && (
                                            <>
                                                <button onClick={() => updateStatus(res.id, ReservationStatus.CONFIRMED)} className="text-green-400 hover:underline">Potvrdit</button>
                                                <button onClick={() => updateStatus(res.id, ReservationStatus.CANCELLED)} className="text-red-400 hover:underline">Zamítnout</button>
                                            </>
                                        )}
                                        {res.status === 'confirmed' && (
                                            <button onClick={() => updateStatus(res.id, ReservationStatus.CANCELLED)} className="text-red-400 hover:underline">Storno</button>
                                        )}
                                    </td>
                                </tr>
                            ))}
                        </tbody>
                    </table>
                </div>
            </div>

            {/* Opening Hours Settings (Mock) */}
            <div className="bg-[#0f3d26] p-6 rounded-lg border border-gold/20">
