           <img src={IMAGES.massage2} alt="Atmosphere" className="w-full h-full object-cover opacity-80 hover:opacity-100 transition duration-500" />
           <img src={IMAGES.massage4} alt="Candles" className="w-full h-full object-cover opacity-80 hover:opacity-100 transition duration-500" />
           <img src={IMAGES.massage5} alt="Oils" className="w-full h-full object-cover opacity-80 hover:opacity-100 transition duration-500" />
           <img src={IMAGES.massage6} alt="Relax" className="w-full h-full object-cover opacity-80 hover:opacity-100 transition duration-500" />
        </div>

        <Services />
        <ReservationSystem />
        <Reviews />
      </main>
      <Footer />

      {/* Floating Admin Link for Demo Purposes */}
      <a href="#admin" className="fixed bottom-2 right-2 text-[10px] text-gray-700 hover:text-gold opacity-50">Admin</a>
    </div>
  );
};

